import React, {useEffect, useState} from 'react';
import {useNavigate, useOutletContext} from 'react-router-dom';
import {getJobPostingListForMyTask} from '../../api/jobApi';
import {JobPostingData} from '../../interface/JobPostingData';
import {EmptyState} from "../../components/common/EmptyStateProps";

interface OutletContextType {
    workTypeFilter: string;
    setLoading: (loading: boolean) => void;
}

export default function MyTaskPage() {
    const navigate = useNavigate();
        const {workTypeFilter, setLoading} = useOutletContext<OutletContextType>();
    const [activeTab, setActiveTab] = useState('matching');
    const [jobList, setJobList] = useState<JobPostingData[]>([]);

    useEffect(() => {
        fetchJobList();
    }, [workTypeFilter, activeTab]);

    const fetchJobList = async () => {
        try {
            const params = {
                workType: workTypeFilter === 'ALL' ? '' : workTypeFilter,
                status: activeTab // 'matching', 'ongoing', 'completed' 등
            };
            const response = await getJobPostingListForMyTask(params);
            setJobList(response.data);
        } catch (error) {
            console.error('Failed to fetch job list:', error);
        }finally {
            setLoading(false);
        }
    };

    const scrollToTop = () => {
        window.scrollTo({top: 0, behavior: 'smooth'});
    };

    const handleDetailClick = (jobPostingCode: string) => {
        navigate(`/announcement/${jobPostingCode}`);
    };
    if (!jobList || jobList.length === 0) {
        return <EmptyState message="등록한 일감이 없습니다."/>;
    }

    return (
        <div>
            <main>
                <button type="button" className="top-btn" onClick={scrollToTop}>
                    <i className="fa-solid fa-chevron-up"></i>
                    <span className="blind">맨위로</span>
                </button>
                <section>
                    <div className="inner">
                        {jobList.map((job) => (
                            <div key={job.jobPostingCode} className="round-box">
                                <div className="round-body">
                                    <div className="info-row">
                                        <span className="location-tit">{job.address}</span>
                                        <div className={`flag ${job.workType === 'HOURLY' ? '' : 'gray'}`}>
                                            {job.workType === 'HOURLY' ? '시간제' : '종일제'}
                                        </div>
                                    </div>
                                    <div className="info-row top-line">
                                        <span className="label">공고</span>
                                        <span className="cont">{job.serviceType}</span>
                                    </div>
                                    <div className="info-row">
                                        <span className="label">어르신 이름</span>
                                        <span className="cont">{job.elderName}</span>
                                    </div>
                                    <div className="info-row">
                                        <span className="label">시작일</span>
                                        <span className="cont">{job.careStartDate}</span>
                                    </div>
                                    <div className="info-row">
                                        <span className="label">간병기간</span>
                                        <span className="cont">{job.careDayCount}일</span>
                                    </div>
                                    <div className="info-row top-line">
                                        <span className="label">비용({job.workType === 'HOURLY' ? '시급' : '일급'})</span>
                                        <span className="cont">{job.dailyPay?.toLocaleString()}원</span>
                                    </div>
                                    <div className="info-row">
                                        <span className="label">비용협의</span>
                                        <span className="cont">{job.payNegotiable}</span>
                                    </div>
                                    <div className="info-row foot">
                                        <span className="status">{job.status}</span>
                                        <a
                                            className="foot-line-btn"
                                            onClick={() => handleDetailClick(job.jobPostingCode)}
                                        >
                                            <i className="fa-solid fa-magnifying-glass"></i>공고 자세히 보기
                                        </a>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </section>
            </main>
        </div>
    );
}
